package orphan
import ("testing";"time")
func TestDetectorBasic(t *testing.T){d:=NewDetector();d.RegisterResource(&Resource{ID:"r1",Type:"session",CreatedAt:time.Now(),LastUsed:time.Now().Add(-3*time.Hour)});d.AddPolicy(Policy{Name:"stale",Type:"session",MaxIdle:1*time.Hour});orphans:=d.Scan();t.Logf("found %d orphans",len(orphans))}
func TestDetectorNoOrphans(t *testing.T){d:=NewDetector();d.RegisterResource(&Resource{ID:"r2",Type:"session",CreatedAt:time.Now(),LastUsed:time.Now()});d.AddPolicy(Policy{Name:"stale",Type:"session",MaxIdle:1*time.Hour});orphans:=d.Scan();if len(orphans)!=0{t.Error("should be 0")}}
func TestAutoClean(t *testing.T){d:=NewDetector();cleaned:=0;d.SetCleanup(func(r*Resource)error{cleaned++;return nil});d.RegisterResource(&Resource{ID:"r3",Type:"session",CreatedAt:time.Now().Add(-5*time.Hour),LastUsed:time.Now().Add(-4*time.Hour)});d.AddPolicy(Policy{Name:"stale",Type:"session",MaxIdle:30*time.Minute,AutoClean:true});orphans:=d.Scan();c,_:=d.Clean(orphans);t.Logf("cleaned %d",c)}
func TestTouch(t *testing.T){d:=NewDetector();d.RegisterResource(&Resource{ID:"t1",Type:"cache",LastUsed:time.Now().Add(-3*time.Hour)});d.Touch("t1");d.AddPolicy(Policy{Name:"exp",Type:"cache",MaxIdle:1*time.Hour});orphans:=d.Scan();if len(orphans)!=0{t.Error("touch should prevent")}}
